CREATE OR REPLACE FUNCTION to_pnumber (adc_amount bigint , as_mask text default null) RETURNS varchar AS $body$
BEGIN
  -- แปลงเป็น เปอร์เซนต์(%)
  return trim(both to_char(adc_amount*100,coalesce(as_mask,'999,999.9999')))||'%';
end;
